2	 * yoke status — poll GET /api/workflows and print a table.
3	 *
4	 * Columns: id (truncated), name, status, current_stage, active sessions.
5	 *
6	 * Server URL discovery order:
7	 *   1. --url flag
8	 *   2. .yoke/server.json in cwd (written by yoke start)
9	 *   3. Default http://127.0.0.1:7777
10	 *
11	 * Review criteria:
12	 *   RC: ECONNREFUSED → clear human-readable message (not a raw stack trace).
13	 *   RC: No shell-injection risk (no child_process here).
14	 */
15	
16	import fs from 'node:fs';
17	import path from 'node:path';
18	import type { Command } from 'commander';
19	
20	// ---------------------------------------------------------------------------
21	// Types
22	// ---------------------------------------------------------------------------
23	
24	export interface WorkflowRow {
25	  id: string;
26	  name: string;
27	  status: string;
28	  current_stage: string | null;
29	  active_sessions: number;
30	}
31	
32	interface WorkflowsResponse {
33	  workflows: WorkflowRow[];
34	  hasMore: boolean;
35	}
