38	// Server URL discovery
39	// ---------------------------------------------------------------------------
40	
41	/**
42	 * Resolve server URL from options, .yoke/server.json, or default.
43	 * @param explicitUrl  Value from --url flag (may be undefined).
44	 * @param cwd          Working directory to search for server.json.
45	 */
46	export function resolveServerUrl(explicitUrl?: string, cwd?: string): string {
47	  if (explicitUrl) return explicitUrl;
48	
49	  const serverJson = path.join(cwd ?? process.cwd(), '.yoke', 'server.json');
50	  if (fs.existsSync(serverJson)) {
51	    try {
52	      const info = JSON.parse(fs.readFileSync(serverJson, 'utf8')) as { url?: string };
53	      if (info.url) return info.url;
54	    } catch {
55	      // Malformed server.json — fall through to default.
56	    }
57	  }
58	
59	  return 'http://127.0.0.1:7777';
60	}
61	
62	// ---------------------------------------------------------------------------
63	// HTTP fetch helper
64	// ---------------------------------------------------------------------------
65	
66	/**
67	 * Fetches GET /api/workflows from the running Yoke server.
68	 * Converts ECONNREFUSED to a human-readable error.
69	 *
70	 * @param serverUrl  Base URL of the running server.
71	 * @param fetcher    Injectable fetch for tests (default: global fetch).
72	 */
73	export async function fetchWorkflows(
74	  serverUrl: string,
75	  fetcher: typeof fetch = fetch,
76	): Promise<WorkflowsResponse> {
77	  let res: Response;
78	  try {
79	    res = await fetcher(`${serverUrl}/api/workflows?limit=100`);
80	  } catch (err: unknown) {
81	    const isConnRefused =
82	      (err as { code?: string }).code === 'ECONNREFUSED' ||
83	      (err as { cause?: { code?: string } }).cause?.code === 'ECONNREFUSED' ||
84	      String(err).includes('ECONNREFUSED');
85	    if (isConnRefused) {
86	      throw new Error(
87	        `Cannot connect to Yoke server at ${serverUrl}.\n` +
88	          `Make sure the server is running: yoke start`,
89	      );
90	    }
91	    throw err;
92	  }
93	
94	  if (!res.ok) {
95	    throw new Error(`Server returned ${res.status}: ${await res.text()}`);
96	  }
97	
98	  return res.json() as Promise<WorkflowsResponse>;
99	}
100	
101	// ---------------------------------------------------------------------------
102	// Table formatter
103	// ---------------------------------------------------------------------------
104	
105	/** Pad string to width, truncating with … if too long. */
106	function col(s: string, width: number): string {
107	  const str = s ?? '';
108	  if (str.length > width) return str.slice(0, width - 1) + '…';
109	  return str.padEnd(width);
110	}
