112	/**
113	 * Format workflow rows as a plain-text table.
114	 * Exported so tests can assert on table structure.
115	 */
116	export function formatWorkflowTable(workflows: WorkflowRow[]): string {
117	  const ID_W = 10;
118	  const NAME_W = 24;
119	  const STATUS_W = 18;
120	  const STAGE_W = 20;
121	  const SESS_W = 8;
122	
123	  const header =
124	    col('ID', ID_W) +
125	    '  ' +
126	    col('NAME', NAME_W) +
127	    '  ' +
128	    col('STATUS', STATUS_W) +
129	    '  ' +
130	    col('STAGE', STAGE_W) +
131	    '  ' +
132	    col('SESSIONS', SESS_W);
133	
134	  const sep = '-'.repeat(header.length);
135	
136	  if (workflows.length === 0) {
137	    return [header, sep, '(no workflows)'].join('\n');
138	  }
139	
140	  const rows = workflows.map((w) =>
141	    [
142	      col(w.id.slice(0, ID_W), ID_W),
143	      '  ',
144	      col(w.name, NAME_W),
145	      '  ',
146	      col(w.status, STATUS_W),
147	      '  ',
148	      col(w.current_stage ?? '—', STAGE_W),
149	      '  ',
150	      String(w.active_sessions ?? 0).padStart(SESS_W),
151	    ].join(''),
152	  );
153	
154	  return [header, sep, ...rows].join('\n');
155	}
156	
157	// ---------------------------------------------------------------------------
158	// Commander registration
159	// ---------------------------------------------------------------------------
160	
161	export function register(program: Command): void {
162	  program
163	    .command('status')
164	    .description('Poll workflow state and print a table')
165	    .option('--url <url>', 'Yoke server URL (overrides .yoke/server.json and default)')
166	    .action(async (opts: { url?: string }) => {
167	      const serverUrl = resolveServerUrl(opts.url);
168	
169	      let data: WorkflowsResponse;
170	      try {
171	        data = await fetchWorkflows(serverUrl);
172	      } catch (err) {
173	        console.error(`Error: ${(err as Error).message}`);
174	        process.exit(1);
175	      }
176	
177	      console.log(formatWorkflowTable(data.workflows));
178	      if (data.hasMore) {
179	        console.log('(more workflows not shown — use the dashboard for full list)');
180	      }
181	    });
182	}
