1	/**
2	 * ScriptedProcessManager — testability seam for the ProcessManager interface.
3	 *
4	 * Replays a recorded stream-json fixture file instead of spawning a real child
5	 * process. Enables deterministic testing of the Pipeline Engine and the
6	 * session lifecycle without running a real agent.
7	 *
8	 * Fixture format (JSONL, one JSON object per line):
9	 *   { "type": "stdout", "line": "<raw stream-json line>" }
10	 *   { "type": "stderr", "chunk": "<stderr text>" }
11	 *   { "type": "exit",   "code": 0 }
12	 *
13	 * The manager emits events in fixture order. An implicit exit(0) is appended
14	 * if the fixture file ends without an exit record. All events are emitted
15	 * asynchronously (setImmediate) to match real process semantics and allow
16	 * callers to register listeners synchronously after spawn() returns.
17	 *
18	 * The ScriptedSpawnHandle uses a deterministic fake pid derived from the
19	 * fixture path hash so multiple concurrent handles have distinct pids.
20	 *
21	 * yoke record writes a .yoke/record.json marker; the pipeline engine reads
22	 * the marker at session-spawn time and uses this manager in capture mode.
23	 * This module implements replay only — capture mode is wired by the
24	 * orchestration layer, not by this module.
25	 */
26	
27	import { EventEmitter } from 'node:events';
28	import fs from 'node:fs';
29	import { createInterface } from 'node:readline';
30	import { ProcessError, type ProcessManager, type SpawnHandle, type SpawnOpts } from './manager.js';
31	
32	// ---------------------------------------------------------------------------
33	// Fixture types
34	// ---------------------------------------------------------------------------
35	
36	type FixtureRecord =
37	  | { type: 'stdout'; line: string }
38	  | { type: 'stderr'; chunk: string }
39	  | { type: 'exit'; code: number };
40	
41	// ---------------------------------------------------------------------------
42	// ScriptedSpawnHandle
43	// ---------------------------------------------------------------------------
44	
45	/**
46	 * A SpawnHandle that replays fixture records as typed events.
47	 * All event emissions are deferred via setImmediate so listeners registered
48	 * synchronously after spawn() returns receive all events.
49	 */
50	class ScriptedSpawnHandle extends EventEmitter implements SpawnHandle {
51	  readonly pid: number;
52	  readonly pgid: number;
53	
54	  private _alive = true;
55	
56	  constructor(pid: number) {
57	    super();
58	    this.pid = pid;
59	    this.pgid = pid;
60	  }
61	
62	  isAlive(): boolean {
63	    return this._alive;
64	  }
65	
66	  async cancel(): Promise<void> {
67	    this._alive = false;
68	    // Emit synthetic exit as if SIGTERM killed the process.
69	    setImmediate(() => this.emit('exit', null, 'SIGTERM'));
70	  }
71	
72	  /**
73	   * Replay the fixture records, emitting typed events asynchronously.
74	   * Resolves when all records have been emitted.
75	   */
76	  async replay(records: FixtureRecord[]): Promise<void> {
77	    return new Promise((resolve) => {
78	      let i = 0;
79	      const emit = () => {
80	        if (!this._alive || i >= records.length) {
81	          if (this._alive) {
82	            // No explicit exit record — emit implicit exit(0).
83	            this._alive = false;
84	            this.emit('exit', 0, null);
85	          }
86	          resolve();
87	          return;
88	        }
89	
90	        const rec = records[i++];
91	        if (rec.type === 'stdout') {
92	          this.emit('stdout_line', rec.line);
93	        } else if (rec.type === 'stderr') {
94	          this.emit('stderr_data', rec.chunk);
95	        } else if (rec.type === 'exit') {
96	          this._alive = false;
97	          this.emit('exit', rec.code, null);
98	          resolve();
99	          return;
100	        }
101	        setImmediate(emit);
102	      };
103	      setImmediate(emit);
104	    });
105	  }
106	
107	  // Typed event overloads — satisfy SpawnHandle interface.
108	  // The implementation signature uses `any` so the overloads can co-exist
109	  // with EventEmitter's broader string signature (TS2394 workaround).
110	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
111	  on(event: 'stdout_line', listener: (line: string) => void): this;
112	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
113	  on(event: 'stderr_data', listener: (chunk: string) => void): this;
114	  on(event: 'stderr_cap_reached', listener: () => void): this;
115	  on(
116	    event: 'exit',
117	    listener: (code: number | null, signal: NodeJS.Signals | null) => void,
118	  ): this;
119	  on(event: 'error', listener: (err: ProcessError) => void): this;
120	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
121	  on(event: string | symbol, listener: (...args: any[]) => void): this {
122	    return super.on(event, listener);
123	  }
124	
125	  once(event: 'stdout_line', listener: (line: string) => void): this;
126	  once(event: 'stderr_data', listener: (chunk: string) => void): this;
127	  once(event: 'stderr_cap_reached', listener: () => void): this;
128	  once(
129	    event: 'exit',
130	    listener: (code: number | null, signal: NodeJS.Signals | null) => void,
131	  ): this;
132	  once(event: 'error', listener: (err: ProcessError) => void): this;
133	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
134	  once(event: string | symbol, listener: (...args: any[]) => void): this {
135	    return super.once(event, listener);
136	  }
137	
138	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
139	  off(event: string | symbol, listener: (...args: any[]) => void): this {
140	    return super.off(event, listener);
141	  }
142	}
143	
144	// ---------------------------------------------------------------------------
145	// ScriptedProcessManager
146	// ---------------------------------------------------------------------------
147	
148	export interface ScriptedManagerOptions {
149	  /**
150	   * Path to the JSONL fixture file to replay.
151	   * Each line must be a JSON object matching FixtureRecord.
152	   */
153	  fixturePath: string;
154	  /**
155	   * Fake PID to assign to the spawned handle.
156	   * Default: a deterministic value derived from the fixture path.
157	   */
158	  fakePid?: number;
159	}
160	
161	/**
162	 * Parse a JSONL fixture file into an array of FixtureRecord objects.
163	 * Skips blank lines and lines that cannot be parsed as valid FixtureRecord.
164	 */
165	export function parseFixture(fixturePath: string): FixtureRecord[] {
166	  const raw = fs.readFileSync(fixturePath, 'utf8');
167	  const records: FixtureRecord[] = [];
168	
169	  for (const line of raw.split('\n')) {
170	    const trimmed = line.trim();
171	    if (!trimmed) continue;
172	
173	    let obj: unknown;
174	    try {
175	      obj = JSON.parse(trimmed);
176	    } catch {
177	      // Skip malformed lines.
178	      continue;
179	    }
180	
181	    if (
182	      typeof obj !== 'object' ||
183	      obj === null ||
184	      !('type' in obj)
185	    ) continue;
186	
187	    const rec = obj as Record<string, unknown>;
188	
189	    if (rec.type === 'stdout' && typeof rec.line === 'string') {
190	      records.push({ type: 'stdout', line: rec.line });
191	    } else if (rec.type === 'stderr' && typeof rec.chunk === 'string') {
192	      records.push({ type: 'stderr', chunk: rec.chunk });
193	    } else if (rec.type === 'exit' && typeof rec.code === 'number') {
194	      records.push({ type: 'exit', code: rec.code });
195	    }
196	    // Unknown types are silently skipped.
197	  }
198	
199	  return records;
200	}
201	
202	/**
203	 * Derive a deterministic fake PID from a fixture path string.
204	 * Avoids collisions between concurrently running scripted handles.
205	 */
206	function deriveFakePid(fixturePath: string): number {
207	  let hash = 0;
208	  for (let i = 0; i < fixturePath.length; i++) {
209	    hash = (hash * 31 + fixturePath.charCodeAt(i)) | 0;
210	  }
211	  // Keep in the range 90000–99999 to avoid real PID collisions.
212	  return 90000 + (Math.abs(hash) % 10000);
213	}
214	
215	/**
216	 * ProcessManager implementation that replays a recorded JSONL fixture.
217	 *
218	 * spawn() returns a handle immediately. The handle begins replaying records
219	 * on the next event-loop tick so callers can register listeners synchronously.
220	 * The replay runs to completion without waiting for acknowledgment — this
221	 * matches the real process manager where stdout lines arrive whenever the
222	 * child writes them.
223	 */
224	export class ScriptedProcessManager implements ProcessManager {
225	  private readonly fixturePath: string;
226	  private readonly fakePid: number;
227	
228	  constructor(opts: ScriptedManagerOptions) {
229	    this.fixturePath = opts.fixturePath;
230	    this.fakePid = opts.fakePid ?? deriveFakePid(opts.fixturePath);
231	  }
232	
233	  async spawn(_opts: SpawnOpts): Promise<SpawnHandle> {
234	    const records = parseFixture(this.fixturePath);
235	    const handle = new ScriptedSpawnHandle(this.fakePid);
236	    // Start replay on the next tick — callers register listeners synchronously
237	    // after spawn() returns before any events fire.
238	    void handle.replay(records);
239	    return handle;
240	  }
241	}
