180	      const rows = db.reader().prepare(sql).all(...params) as WorkflowRow[];
181	      const hasMore = rows.length > limit;
182	      const workflows = hasMore ? rows.slice(0, limit) : rows;
183	
184	      return reply.send({
185	        workflows,
186	        hasMore,
187	        nextBefore: hasMore ? workflows[workflows.length - 1].created_at : null,
188	      });
189	    },
190	  );
