192	  // GET /api/workflows/:id/timeline
193	  // Merged SQLite events + JSONL (§Obs, D34).
194	  fastify.get(
195	    '/api/workflows/:id/timeline',
196	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
197	      const { id } = req.params;
198	      const reader = db.reader();
199	
200	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
201	      if (!wf) return notFound(reply, 'workflow not found');
202	
203	      const events = reader
204	        .prepare(
205	          'SELECT id, ts, workflow_id, item_id, session_id, stage, phase, attempt, event_type, level, message, extra FROM events WHERE workflow_id = ? ORDER BY ts, id',
206	        )
207	        .all(id) as Array<{
