234	  fastify.get(
235	    '/api/sessions/:id/log',
236	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
237	      const { id } = req.params;
238	      const qs = req.query as Record<string, string | undefined>;
