241	      const limitRaw = qs.limit !== undefined ? parseInt(qs.limit, 10) : 100;
242	
243	      if (!isFinite(sinceSeqRaw) || sinceSeqRaw < 0) return badRequest(reply, 'sinceSeq must be a non-negative integer');
