287	      // Map groupBy dimension to SQLite column.
288	      const groupCol: Record<string, string> = {
289	        feature: 'item_id',
290	        phase: 'phase',
291	        profile: 'agent_profile',
292	        session: 'id',
293	      };
294	      const col = groupCol[groupBy];
295	
296	      const rows = reader
297	        .prepare(
298	          `SELECT ${col} AS dimension,
299	                  SUM(input_tokens) AS input_tokens,
300	                  SUM(output_tokens) AS output_tokens,
301	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
302	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
303	                  COUNT(*) AS session_count
304	           FROM sessions
305	           WHERE workflow_id = ?
306	           GROUP BY ${col}
307	           ORDER BY input_tokens DESC`,
308	        )
309	        .all(id);
310	
311	      return reply.send({ workflowId: id, groupBy, rows });
312	    },
313	  );
314	
315	  // GET /api/workflows/:id/usage/timeseries?bucket=hour|day
316	  // Usage timeseries bucketed by hour or day.
317	  fastify.get(
318	    '/api/workflows/:id/usage/timeseries',
319	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
320	      const { id } = req.params;
321	      const qs = req.query as Record<string, string | undefined>;
322	      const bucket = qs.bucket ?? 'hour';
323	
324	      if (bucket !== 'hour' && bucket !== 'day') {
325	        return badRequest(reply, 'bucket must be hour or day');
326	      }
327	
328	      const reader = db.reader();
329	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
330	      if (!wf) return notFound(reply, 'workflow not found');
331	
332	      // SQLite strftime format for the requested bucket.
333	      const fmt = bucket === 'hour' ? '%Y-%m-%dT%H:00:00Z' : '%Y-%m-%dT00:00:00Z';
334	
335	      const rows = reader
336	        .prepare(
337	          `SELECT strftime('${fmt}', started_at) AS bucket,
338	                  SUM(input_tokens) AS input_tokens,
339	                  SUM(output_tokens) AS output_tokens,
340	                  SUM(cache_creation_input_tokens) AS cache_creation_input_tokens,
341	                  SUM(cache_read_input_tokens) AS cache_read_input_tokens,
342	                  COUNT(*) AS session_count
343	           FROM sessions
344	           WHERE workflow_id = ?
345	           GROUP BY bucket
346	           ORDER BY bucket ASC`,
347	        )
348	        .all(id);
349	
350	      return reply.send({ workflowId: id, bucket, rows });
351	    },
352	  );
353	
354	  // POST /api/workflows/:id/control
355	  // Idempotent manual control (mirrors WS control frame).
356	  fastify.post(
357	    '/api/workflows/:id/control',
358	    async (req: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
359	      const { id } = req.params;
360	      const body = req.body as {
361	        commandId?: string;
362	        action?: string;
363	        itemId?: string;
364	        stageId?: string;
365	        extra?: unknown;
366	      } | null;
367	
368	      if (!body?.commandId) return badRequest(reply, 'commandId is required');
369	      if (!body.action) return badRequest(reply, 'action is required');
370	
371	      const reader = db.reader();
372	      const wf = reader.prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
373	      if (!wf) return notFound(reply, 'workflow not found');
374	
375	      // Idempotency check (AC-4, RC: not by re-executing).
376	      const cached = idempotency.get(body.commandId);
377	      if (cached !== undefined) {
378	        return reply.status(200).send(cached);
379	      }
380	
381	      // Cache and return accepted response. Actual execution deferred to pipeline engine.
382	      const response = {
383	        status: 'accepted',
384	        commandId: body.commandId,
385	        workflowId: id,
386	        action: body.action,
387	      };
388	      idempotency.set(body.commandId, response);
389	
390	      return reply.status(202).send(response);
391	    },
392	  );
393	
394	  // POST /api/workflows/:id/attention/:attentionId/ack
395	  // Clear a pending attention item.
396	  // The write is delegated to callbacks.ackAttention (RC-3 — no writes in API layer).
397	  fastify.post(
398	    '/api/workflows/:id/attention/:attentionId/ack',
399	    async (
400	      req: FastifyRequest<{ Params: { id: string; attentionId: string } }>,
401	      reply: FastifyReply,
402	    ) => {
403	      const { id, attentionId } = req.params;
404	      const attId = parseInt(attentionId, 10);
405	      if (!isFinite(attId)) return badRequest(reply, 'attentionId must be an integer');
406	
407	      if (!callbacks.ackAttention) {
408	        return reply.status(501).send({ error: 'attention ack not configured' });
409	      }
410	
411	      // Verify the workflow exists using the read-only connection.
412	      const wf = db.reader().prepare('SELECT id FROM workflows WHERE id = ?').get(id) as { id: string } | undefined;
413	      if (!wf) return notFound(reply, 'workflow not found');
414	
415	      // Delegate the pending_attention read + write to the injected callback
416	      // so that no SQLite write occurs inside the API layer (RC-3).
417	      const result = callbacks.ackAttention(id, attId);
418	      if (result.status === 'not_found') return notFound(reply, 'attention item not found');
419	      return reply.send(result);
420	    },
421	  );
422	
423	  return { fastify, state: { seqStore, backfillBuffer, idempotency } };
424	}
425	
426	// ---------------------------------------------------------------------------
427	// Convenience: listen with enforced 127.0.0.1 binding (AC-6, RC)
428	// ---------------------------------------------------------------------------
429	
430	/**
431	 * Creates the server and starts listening on 127.0.0.1. Throws if host is
432	 * anything other than '127.0.0.1' — no 0.0.0.0 bind path exists (D57).
433	 *
434	 * @returns The listening Fastify instance.
435	 */
436	export async function listenServer(
437	  db: DbPool,
438	  opts: ServerOptions = {},
439	  callbacks: ServerCallbacks = {},
440	): Promise<FastifyInstance> {
441	  const host = opts.host ?? '127.0.0.1';
442	  if (host !== '127.0.0.1') {
443	    throw new Error(`Server must bind to 127.0.0.1, not ${host} (D57)`);
444	  }
445	  const port = opts.port ?? 0;
446	
447	  const { fastify } = await createServer(db, callbacks);
448	  await fastify.listen({ host, port });
449	  return fastify;
450	}
